from Crypto.Cipher import AES
from Crypto.Random import get_random_bytes
from cryptography.fernet import Fernet
import os

def generate_key():
    return Fernet.generate_key()

def load_key():
    if not os.path.exists('encryption_key.bin'):
        key = generate_key()
        with open('encryption_key.bin', 'wb') as key_file:
            key_file.write(key)

    with open('encryption_key.bin', 'rb') as key_file:
        return Fernet.from_key(key_file.read())

def encrypt_card_number(card_number, key):
    f = Fernet(key)
    encrypted = f.encrypt(card_number.encode()).decode()
    return encrypted

def decrypt_card_number(encrypted_card_number, key):
    f = Fernet(key)
    decrypted = f.decrypt(encrypted_card_number.encode())
    return decrypted.decode()